def validate(args, output):
    head = args[0]
    # collect the list's values in order from its wire form
    vals = list(head) if head else []
    # rebuild the returned tree from its level-order wire form
    def deser(a):
        if not a:
            return None
        root = [a[0], None, None]
        q = [root]; i = 1
        while q and i < len(a):
            node = q.pop(0)
            if i < len(a):
                if a[i] is not None:
                    node[1] = [a[i], None, None]; q.append(node[1])
                i += 1
            if i < len(a):
                if a[i] is not None:
                    node[2] = [a[i], None, None]; q.append(node[2])
                i += 1
        return root
    root = deser(output)
    # in-order traversal must reproduce the list's values in their original order
    ino = []
    st, node = [], root
    while st or node:
        while node:
            st.append(node); node = node[1]
        node = st.pop(); ino.append(node[0]); node = node[2]
    if ino != vals:
        return False
    # every node's subtree heights differ by at most 1 (height-balanced)
    def height(n):
        if n is None:
            return 0, True
        hl, bl = height(n[1])
        hr, br = height(n[2])
        ok = bl and br and abs(hl - hr) <= 1
        return max(hl, hr) + 1, ok
    _, balanced = height(root)
    return balanced

