class Solution:
    def sortedListToBST(self, head):
        # independent construction: copy the list to an array, same lower-middle
        # choice so the canonical tree matches the optimal byte for byte
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        def build(arr):
            if not arr:
                return None
            mid = (len(arr) - 1) // 2
            t = TreeNode(arr[mid])
            t.left = build(arr[:mid])
            t.right = build(arr[mid + 1:])
            return t
        return build(vals)

