class Solution:
    def sortedListToBST(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        def build(lo, hi):
            if lo > hi:
                return None
            mid = (lo + hi) // 2
            t = TreeNode(vals[mid])
            t.left = build(lo, mid - 1)
            t.right = build(mid + 1, hi)
            return t
        return build(0, len(vals) - 1)

